import Fuse from 'https://cdn.jsdelivr.net/npm/fuse.js@7/+esm';
const fuse = new Fuse(data.records, { keys: data.keys, includeScore: true, includeMatches: data.includeMatches ?? false, threshold: data.threshold ?? 0.6, ignoreLocation: data.ignoreLocation ?? false, isCaseSensitive: data.isCaseSensitive ?? false, minMatchCharLength: data.minMatchCharLength ?? 1 });
const limitConfig = data.limit == null ? undefined : { limit: data.limit };
const results = fuse.search(data.query, limitConfig);
